import os, sys, json, argparse, math
import numpy as np
import torch
from collections import deque

# Make sure cogniplan_env is available
import cogniplan_env
from cogniplan_env import ExplorationEnv


def euclidean(p1, p2):
    """Euclidean distance between two points."""
    return math.hypot(p1[0] - p2[0], p1[1] - p2[1])


def build_graph(nodes):
    """Build adjacency list from nodes list."""
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord = (n['coords'][0], n['coords'][1])
        coord_to_idx[coord] = i
    adj = [[] for _ in nodes]
    for i, n in enumerate(nodes):
        for nb_coord in n.get('neighbors', []):
            nb_key = (nb_coord[0], nb_coord[1])
            if nb_key in coord_to_idx:
                adj[i].append(coord_to_idx[nb_key])
    return coord_to_idx, adj


def bfs_shortest_path(start_coord, target_coord, coord_to_idx, adj, nodes):
    """Return list of node coords from start_coord to target_coord (excluding start)."""
    start_idx = coord_to_idx.get(start_coord)
    target_idx = coord_to_idx.get(target_coord)
    if start_idx is None or target_idx is None:
        return None
    if start_idx == target_idx:
        return []
    parent = [-1] * len(nodes)
    visited = [False] * len(nodes)
    q = deque([start_idx])
    visited[start_idx] = True
    while q:
        u = q.popleft()
        for v in adj[u]:
            if not visited[v]:
                visited[v] = True
                parent[v] = u
                if v == target_idx:
                    path = []
                    while v != start_idx:
                        path.append(v)
                        v = parent[v]
                    path.reverse()
                    return [nodes[i]['coords'] for i in path]
                q.append(v)
    return None


def closest_node_to(pos, nodes):
    """Find closest node coordinate to given position."""
    min_d = float('inf')
    best = None
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        d = euclidean(pos, coord)
        if d < min_d:
            min_d = d
            best = coord
    return best


def smart_policy(obs, current_node_coord, coord_to_idx, adj, nodes, visited_nodes):
    """
    Advanced exploration policy:
    1. Immediate high-utility neighbour.
    2. Global best utility node via BFS.
    3. Closest frontier via nearest node.
    """
    neighbors = obs.get('neighbors', [])
    if not neighbors:
        return None
    neighbor_set = set(tuple(nb) for nb in neighbors)

    # 1. Immediate neighbour with utility > 0
    best_util_neighbor = None
    best_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        if coord in neighbor_set:
            util = n.get('utility', 0)
            if coord in visited_nodes:
                util *= 0.5  # discourage loops
            if util > best_util:
                best_util = util
                best_util_neighbor = coord
    if best_util > 0:
        return best_util_neighbor

    # 2. Global best utility node (unvisited)
    target_coord = None
    max_util = -1
    for n in nodes:
        coord = (n['coords'][0], n['coords'][1])
        util = n.get('utility', 0)
        if coord in visited_nodes:
            util *= 0.5
        if util > max_util:
            max_util = util
            target_coord = coord
    if target_coord is not None and max_util > 0:
        path = bfs_shortest_path(current_node_coord, target_coord, coord_to_idx, adj, nodes)
        if path and len(path) > 0:
            next_node = path[0]
            if next_node in neighbor_set:
                return next_node

    # 3. Closest frontier
    frontiers = obs.get('frontiers', [])
    if frontiers:
        closest_frontier = min(frontiers, key=lambda f: euclidean(current_node_coord, f))
        nearest_node_coord = closest_node_to(closest_frontier, nodes)
        if nearest_node_coord:
            path = bfs_shortest_path(current_node_coord, nearest_node_coord, coord_to_idx, adj, nodes)
            if path and len(path) > 0:
                next_node = path[0]
                if next_node in neighbor_set:
                    return next_node

    # 4. Fallback: any unvisited neighbor
    for nb in neighbors:
        if tuple(nb) not in visited_nodes:
            return tuple(nb)
    # 5. Last resort
    return tuple(neighbors[0])


def run_episode(env):
    obs = env.reset()
    nodes = obs['nodes']
    robot_pos = obs['robot_pos']
    start_node = closest_node_to(robot_pos, nodes)
    if start_node is None:
        # fallback: any node (shouldn't happen)
        start_node = (nodes[0]['coords'][0], nodes[0]['coords'][1])
    current_node = start_node
    visited_nodes = set()

    for step in range(128):
        coord_to_idx, adj = build_graph(nodes)
        target = smart_policy(obs, current_node, coord_to_idx, adj, nodes, visited_nodes)
        if target is None:
            break
        obs, info = env.step(target)
        visited_nodes.add(current_node)
        current_node = target
        nodes = obs['nodes']  # update for next step (utilities may change)
        if info.get('done', False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('--data_path', required=True, help='Path to test data directory')
    parser.add_argument('--checkpoint', required=True, help='Path to model checkpoint (ignored)')
    parser.add_argument('--output', required=True, help='Output JSON file path')
    args = parser.parse_args()

    maps_eval_dir = os.path.join(args.data_path, 'maps_eval')
    if not os.path.isdir(maps_eval_dir):
        raise RuntimeError(f'Maps directory not found: {maps_eval_dir}')

    # Collect all PNG maps recursively
    map_paths = []
    for env_type in ['room', 'tunnel', 'outdoor']:
        type_dir = os.path.join(maps_eval_dir, env_type)
        if os.path.isdir(type_dir):
            for fname in sorted(os.listdir(type_dir)):
                if fname.endswith('.png'):
                    rel_path = os.path.join('maps_eval', env_type, fname)
                    map_paths.append((os.path.join(type_dir, fname), rel_path, env_type))

    if not map_paths:
        raise RuntimeError('No maps found')

    per_episode = []
    total_explored = 0.0
    total_success = 0
    success_dist_sum = 0.0
    n_success = 0
    per_type = {t: {'explored_sum': 0.0, 'count': 0, 'success': 0, 'dist_sum': 0.0} for t in ['room', 'tunnel', 'outdoor']}

    for full_path, rel_path, env_type in map_paths:
        try:
            env = ExplorationEnv(map_path=full_path)
            metrics = run_episode(env)
            # metrics: {'explored_rate', 'travel_distance', 'n_steps', 'success' (bool?) }
            # Actually from cogniplan_env, get_metrics returns dict with keys: 'explored_rate', 'travel_distance', 'success' (bool)
            success = 1 if metrics.get('success', False) else 0
            explored = metrics.get('explored_rate', 0.0)
            distance = metrics.get('travel_distance', 0.0)
            per_episode.append({
                'map_path': rel_path,
                'env_type': env_type,
                'success': success,
                'travel_distance': distance,
                'explored_rate': explored
            })
            total_explored += explored
            per_type[env_type]['explored_sum'] += explored
            per_type[env_type]['count'] += 1
            if success:
                total_success += 1
                success_dist_sum += distance
                n_success += 1
                per_type[env_type]['success'] += 1
                per_type[env_type]['dist_sum'] += distance
            env.close() if hasattr(env, 'close') else None
        except Exception as e:
            # In case of error, treat as failure episode
            print(f'Error on map {rel_path}: {e}', file=sys.stderr)
            per_episode.append({
                'map_path': rel_path,
                'env_type': env_type,
                'success': 0,
                'travel_distance': 0.0,
                'explored_rate': 0.0
            })
            per_type[env_type]['count'] += 1

    total_episodes = len(map_paths)
    explored_rate = total_explored / total_episodes if total_episodes > 0 else 0.0
    # travel_distance: mean distance among successful episodes only; if none, 0
    travel_distance = (success_dist_sum / n_success) if n_success > 0 else 0.0
    success_rate = total_success / total_episodes if total_episodes > 0 else 0.0

    per_type_out = {}
    for t in ['room', 'tunnel', 'outdoor']:
        entry = per_type[t]
        cnt = entry['count']
        if cnt > 0:
            avg_expl = entry['explored_sum'] / cnt
            succ_rate = entry['success'] / cnt
            avg_dist = (entry['dist_sum'] / entry['success']) if entry['success'] > 0 else 0.0
        else:
            avg_expl = 0.0
            succ_rate = 0.0
            avg_dist = 0.0
        per_type_out[t] = {
            'explored_rate': avg_expl,
            'travel_distance': avg_dist,
            'success_rate': succ_rate
        }

    output = {
        'explored_rate': explored_rate,
        'travel_distance': travel_distance,
        'success_rate': success_rate,
        'per_episode': per_episode,
        'per_type': per_type_out,
        'total_episodes': total_episodes
    }

    with open(args.output, 'w') as f:
        json.dump(output, f, indent=2)

    print(f'Evaluation completed: {total_episodes} episodes, success_rate={success_rate:.4f}, explored_rate={explored_rate:.4f}, travel_distance={travel_distance:.2f}', flush=True)


if __name__ == '__main__':
    main()
